operations.insert:
/* Clean initial pallet lookup screen */
.grid > main.panel .section-head {
  text-align: center;
}

.grid > main.panel .search-row {
  justify-content: center;
}

.grid > main.panel .search-row .scan-entry-row {
  width: min(30%, 460px);
  min-width: 320px;
  justify-content: center;
}

.grid > main.panel #palletSearchInput {
  text-align: center;
}

.grid > main.panel > .inline-option:first-of-type {
  justify-content: center;
  margin-top: 10px;
}

body:not(.pallet-view-active) .results-head,
body:not(.pallet-view-active) .table-wrap,
body:not(.pallet-view-active) .meta-grid,
body:not(.pallet-view-active) .stacked-panels,
body:not(.pallet-view-active) #duplicateWarning,
body:not(.pallet-view-active) #revisitNotice,
body:not(.pallet-view-active) #scanPanel {
  display: none !important;
}

@media (max-width: 1180px) {
  .grid > main.panel .search-row .scan-entry-row {
    width: min(44%, 520px);
  }
}

@media (max-width: 760px) {
  .grid > main.panel .search-row .scan-entry-row {
    width: 100%;
    min-width: 0;
  }
}
